<?php
 if (!function_exists('fmRequireRuntimePhp')) { function fmRequireRuntimePhp(string $baseDir, string $relativePath): void { $relativeVariants = [$relativePath]; if (strpos($relativePath, '../') === 0) { $relativeVariants[] = preg_replace('#^\.\./#', '', $relativePath, 1); } $candidatePaths = []; foreach ($relativeVariants as $variant) { $minifiedPath = preg_replace('/\.php$/', '.min.php', $variant); $candidatePaths[] = $baseDir . '/' . ltrim($minifiedPath, '/'); $candidatePaths[] = $baseDir . '/' . ltrim($variant, '/'); } foreach ($candidatePaths as $candidatePath) { if (is_file($candidatePath)) { require_once $candidatePath; return; } } throw new RuntimeException('Arquivo PHP não encontrado: ' . $relativePath); } } if (!function_exists('fmLoadRuntimeConfig')) { function fmLoadRuntimeConfig(string $baseDir): array { $candidatePaths = [ $baseDir . '/../../config.php', $baseDir . '/../config.php', $baseDir . '/../../../config.php', $baseDir . '/../../../../config.php', ]; foreach ($candidatePaths as $candidatePath) { if (is_file($candidatePath)) { return require $candidatePath; } } throw new RuntimeException('Arquivo de configuracao nao encontrado.'); } } 